function Weather({ city }) {
  const [forecast, setForecast] = useState(null);
  useEffect(() => {
    loadForecast(city).then(setForecast);
  }, [city]);
  return forecast ? <Forecast data={forecast} /> : <p>Loading…</p>;
}

